mapper.select:
SELECT COUNT(*) FROM saf.tn_saf_cert
WHERE use_end_dt > NOW()
AND oprtr_id = #{oprtrId}
AND batch_id = #{batchId}
AND cert_type_cd = #{certTypeCd}
AND cert_schm_cd = #{certSchmCd}
AND srnd_yn = #{srndYn}

SELECT * FROM saf.tn_saf_cert
WHERE use_end_dt > NOW()
AND oprtr_id = #{oprtrId}
AND batch_id = #{batchId}
AND cert_type_cd = #{certTypeCd}
AND cert_schm_cd = #{certSchmCd}
AND srnd_yn = #{srndYn}
ORDER BY frst_reg_dt DESC
LIMIT #{pageSize} OFFSET #{offset}

mapper.insert:
INSERT INTO saf.tn_saf_cert (
    cert_id, oprtr_id, batch_id, cert_type_cd, cert_schm_cd, cert_no, file_id,
    srnd_yn, use_bgng_dt, use_end_dt,
    frst_reg_dt, frst_reg_user_id, last_chg_dt, last_chg_user_id
) VALUES (
    #{certId}, #{oprtrId}, #{batchId}, #{certTypeCd}, #{certSchmCd}, #{certNo}, #{fileId},
    'N', NOW(), '9999-12-31 23:59:59',
    NOW(), #{frstRegUserId}, NOW(), #{lastChgUserId}
)

mapper.select:
SELECT COALESCE(SUM(1), 0)
FROM saf.tn_saf_cert c
WHERE c.oprtr_id = #{oprtrId}
  AND EXTRACT(YEAR FROM c.frst_reg_dt)::TEXT = #{rprtYr}
  AND c.srnd_yn = 'N'
  AND c.use_end_dt > NOW()
